    } else {
      Node* pre = curr->left;
      while (pre->right && pre->right != curr) pre = pre->right;
      pre->right = curr; 
      curr = curr->left;
    }
  }
}

Node* LCA(Node* root, Node* p, Node* q) {
  if (!root || root == p || root == q) return root;
  Node* left = LCA(root->left, p, q);
  Node* right = LCA(root->right, p, q);
  if (left && right) return root;
  return left ? left : right;
}

int calculate(Node* root, int& maxSum) {
  if (!root) return 0;
  int l = std::max(0, calculate(root->left, maxSum));
  int r = std::max(0, calculate(root->right, maxSum));
  maxSum = std::max(maxSum, l + r + root->data);
  return l + r + root->data; 
}

Node* rotateLeft(Node* x) {
  Node* y = x->right;
  Node* T2 = y->left;
  y->left = x;
  x->right = T2;
  return y;
}

string serialize(Node* root) {
  if (!root) return "#";
  return to_string(root->data) + serialize(root->left) + serialize(root->right);
}

bool isComplete(Node* root, int index, int nodeCount) {
  if (!root) return true;
  if (index >= nodeCount) return false;
  return isComplete(root->left, 2*index + 1, nodeCount) && 
         isComplete(root->right, 2*index + 2, nodeCount);
}

void flatten(Node* root) {
  if (!root) return;
  stack<Node*> s; s.push(root);
  while(!s.empty()) {
    Node* curr = s.top(); s.pop();
    if (curr->right) s.push(curr->right);
    if (curr->left) s.push(curr->left);
    if (!s.empty()) curr->right = s.top();
  }
}

