void update(int si, int ss, int se, int i, int diff) {
  if (i < ss || i > se) return;
  tree[si] += diff;
  if (se != ss) {
    int mid = (ss + se) / 2;
    update(2*si+1, ss, mid, i, diff);
    update(2*si+2, mid+1, se, i, diff);
  }
}

Node* findSuccessor(Node* root, Node* target) {
  if (target->right) return findMin(target->right);
  Node* successor = nullptr;
  while (root) {
    if (root->data > target->data) root = root->left;
    else if (root->data < target->data) root = root->right;
    else break;
  }
  return successor;
}

bool checkRedNodes(Node* root) {
  if (!root) return true;
  if (root->color == RED) {
    if (root->left && root->left->color == RED) return false;
    if (root->right && root->right->color == RED) return false;
  }
  return checkRedNodes(root->left) && checkRedNodes(root->right);
}

void remove(TrieNode* root, string word, int depth) {
  if (depth == word.size()) {
    root->isEndOfWord = false;
    return;
  }
  int index = word[depth] - 'a';
  remove(root->children[index], word, depth + 1);
}

