Node* build(int pre[], int in[], int inStart, int inEnd, int preIndex) {
  if (inStart > inEnd) return nullptr;
  Node* node = new Node(pre[preIndex++]);
  int split = search(in, inStart, inEnd, node->data);
  node->left = build(pre, in, inStart, split - 1, preIndex);
  node->right = build(pre, in, split + 1, inEnd, preIndex);
  return node;
}

