void heapify(int arr[], int n, int i) {
  int largest = i, l = 2*i + 1, r = 2*i + 2;
  if (l < n && arr[l] > arr[largest]) largest = l;
  if (largest != i) {
    std::swap(arr[i], arr[largest]);
    heapify(arr, n, largest);
  }
}

Node* LCA(Node* root, int p, int q) {
  if (!root) return nullptr;
  if (root->data > p && root->data > q) return LCA(root->right, p, q);
  if (root->data < p && root->data < q) return LCA(root->left, p, q);
  return root;
}

bool isIsomorphic(Node* n1, Node* n2) {
  if (!n1 && !n2) return true;
  if (!n1 || !n2 || n1->data != n2->data) return false;
  return (isIsomorphic(n1->left, n2->right) && isIsomorphic(n1->right, n2->left));
}

int diameter(Node* root, int& d) {
  if (!root) return 0;
  int lh = diameter(root->left, d);
  int rh = diameter(root->right, d);
  d = std::max(d, lh + rh);
