void insertLeaf(Node* leaf, int key) {
  int i = leaf->n - 1;
  while (i >= 0 && leaf->keys[i] > key) {
    leaf->keys[i+1] = leaf->keys[i];
    i--;
  }
  leaf->keys[i+1] = key;
  leaf->n++;
}

bool isPerfect(Node* root) {
  if (!root) return true;
  if (!root->left && !root->right) return true;
  if (!root->left || !root->right) return false;
  return isPerfect(root->left) && isPerfect(root->right);
}

int getSum(int si, int ss, int se, int qs, int qe) {
  if (qs <= ss && qe >= se) return tree[si];
  if (se < qs || ss > qe) return 0;
  int mid = ss + se / 2; 
  return getSum(2*si+1, ss, mid, qs, qe) + 
         getSum(2*si+2, mid+1, se, qs, qe);
}

void getBottomView(Node* root, int hd, map<int, int>& m) {
