Node* bstLCA(Node* root, int p, int q) {
  if (!root) return nullptr;
  if (root->data < p && root->data < q) return bstLCA(root->left, p, q);
  if (root->data > p && root->data > q) return bstLCA(root->right, p, q);
  return root;
}

int maxLeafPath(Node* root, int& res) {
  if (!root) return 0;
  if (!root->left && !root->right) return root->data;
  int l = maxLeafPath(root->left, res);
  int r = maxLeafPath(root->right, res);
  res = std::max(res, l + r + root->data);
  return root->data + std::max(l, r);
}

