  while (queue.length) {
    const n = queue.shift()!;
    for (let neighbor of n.neighbors) {
      const copy = new Node(neighbor.val);
      map.get(n)!.neighbors.push(copy);
      queue.push(neighbor);
    }
  }
  return map.get(node);
}

